import{_ as d,o as r,c as o,ag as e}from"./chunks/framework.D_Vktuop.js";const c=JSON.parse('{"title":"nanobot 术语表","description":"","frontmatter":{},"headers":[],"relativePath":"guide/reference/terminology.md","filePath":"guide/reference/terminology.md","lastUpdated":null}'),a={name:"guide/reference/terminology.md"};function n(s,t,l,h,i,g){return r(),o("div",null,[...t[0]||(t[0]=[e('<h1 id="nanobot-术语表" tabindex="-1">nanobot 术语表 <a class="header-anchor" href="#nanobot-术语表" aria-label="Permalink to &quot;nanobot 术语表&quot;">​</a></h1><blockquote><p>统一项目文档中的术语使用，确保表达一致</p></blockquote><p><strong>版本</strong>: v1.0.0 | <strong>更新日期</strong>: 2026-03-12</p><hr><h2 id="核心概念术语" tabindex="-1">核心概念术语 <a class="header-anchor" href="#核心概念术语" aria-label="Permalink to &quot;核心概念术语&quot;">​</a></h2><table tabindex="0"><thead><tr><th>中文术语</th><th>英文术语</th><th>定义/说明</th><th>首次出现文档</th></tr></thead><tbody><tr><td><strong>代理</strong></td><td>Agent</td><td>nanobot 的核心 AI 实体，负责处理消息、调用 LLM、执行工具</td><td><a href="./modules/agent-loop.html">agent-loop.md</a></td></tr><tr><td><strong>通道</strong></td><td>Channel</td><td>连接不同聊天平台的适配层，如 Telegram、Discord 等</td><td><a href="./modules/channels.html">channels.md</a></td></tr><tr><td><strong>消息总线</strong></td><td>MessageBus</td><td>解耦通道和代理的异步消息队列系统</td><td><a href="./modules/message-bus.html">message-bus.md</a></td></tr><tr><td><strong>工具</strong></td><td>Tool</td><td>AI 可以执行的具体操作，如读文件、执行命令、搜索网页</td><td><a href="./modules/tools.html">tools.md</a></td></tr><tr><td><strong>技能</strong></td><td>Skill</td><td>教 AI 如何完成特定任务的 Markdown 文件</td><td><a href="./modules/skills.html">skills.md</a></td></tr><tr><td><strong>会话</strong></td><td>Session</td><td>保存对话历史和元数据的对象</td><td><a href="./modules/session.html">session.md</a></td></tr><tr><td><strong>提供商</strong></td><td>Provider</td><td>提供大模型语言模型服务的第三方服务商</td><td><a href="./modules/providers.html">providers.md</a></td></tr><tr><td><strong>子代理</strong></td><td>Subagent</td><td>在后台独立执行任务的代理实例</td><td><a href="./modules/subagent.html">subagent.md</a></td></tr><tr><td><strong>上下文</strong></td><td>Context</td><td>发送给 LLM 的完整信息，包括系统提示词、历史对话、工具定义等</td><td><a href="./modules/context-builder.html">context-builder.md</a></td></tr><tr><td><strong>记忆</strong></td><td>Memory</td><td>长期存储的信息，包括 MEMORY.md（重要事实）和 HISTORY.md（历史日志）</td><td><a href="./modules/memory.html">memory.md</a></td></tr></tbody></table><hr><h2 id="技术架构术语" tabindex="-1">技术架构术语 <a class="header-anchor" href="#技术架构术语" aria-label="Permalink to &quot;技术架构术语&quot;">​</a></h2><table tabindex="0"><thead><tr><th>中文术语</th><th>英文术语</th><th>定义/说明</th><th>首次出现文档</th></tr></thead><tbody><tr><td><strong>入站消息</strong></td><td>Inbound Message</td><td>从聊天平台发往代理的消息</td><td><a href="./flow-analysis/message-flow.html">message-flow.md</a></td></tr><tr><td><strong>出站消息</strong></td><td>Outbound Message</td><td>从代理发往聊天平台的响应消息</td><td><a href="./flow-analysis/message-flow.html">message-flow.md</a></td></tr><tr><td><strong>会话密钥</strong></td><td>Session Key</td><td>唯一标识一个会话的字符串，格式为 <code>channel:chat_id</code></td><td><a href="./modules/session.html">session.md</a></td></tr><tr><td><strong>工具调用</strong></td><td>Tool Call</td><td>LLM 请求执行某个工具的操作</td><td><a href="./modules/agent-loop.html">agent-loop.md</a></td></tr><tr><td><strong>迭代</strong></td><td>Iteration</td><td>代理循环中的一次 LLM 调用和工具执行过程</td><td><a href="./modules/agent-loop.html">agent-loop.md</a></td></tr><tr><td><strong>记忆合并</strong></td><td>Consolidation</td><td>将旧对话压缩为长期记忆的过程</td><td><a href="./modules/memory.html">memory.md</a></td></tr><tr><td><strong>注册表</strong></td><td>Registry</td><td>管理可扩展组件（工具、提供商等）的映射表</td><td><a href="./modules/tools.html">tools.md</a></td></tr><tr><td><strong>工作空间</strong></td><td>Workspace</td><td>nanobot 存储数据（会话、技能、记忆）的目录</td><td><a href="./overview/introduction.html">introduction.md</a></td></tr><tr><td><strong>运行时目录</strong></td><td>Runtime Directory</td><td>从配置文件路径派生的运行数据目录</td><td><a href="./overview/directory-structure.html">directory-structure.md</a></td></tr></tbody></table><hr><h2 id="设计模式术语" tabindex="-1">设计模式术语 <a class="header-anchor" href="#设计模式术语" aria-label="Permalink to &quot;设计模式术语&quot;">​</a></h2><table tabindex="0"><thead><tr><th>中文术语</th><th>英文术语</th><th>定义/说明</th><th>首次出现文档</th></tr></thead><tbody><tr><td><strong>消息总线模式</strong></td><td>Message Bus Pattern</td><td>使用消息队列解耦组件的架构模式</td><td><a href="./patterns/architectural-patterns.html">architectural-patterns.md</a></td></tr><tr><td><strong>插件模式</strong></td><td>Plugin Pattern</td><td>允许动态扩展功能的架构模式</td><td><a href="./patterns/design-patterns.html">design-patterns.md</a></td></tr><tr><td><strong>命令模式</strong></td><td>Command Pattern</td><td>将请求封装为对象的设计模式</td><td><a href="./patterns/design-patterns.html">design-patterns.md</a></td></tr><tr><td><strong>注册表模式</strong></td><td>Registry Pattern</td><td>集中管理和查找可扩展组件的模式</td><td><a href="./patterns/design-patterns.html">design-patterns.md</a></td></tr><tr><td><strong>工厂模式</strong></td><td>Factory Pattern</td><td>创建对象的接口由子类决定的模式</td><td><a href="./patterns/design-patterns.html">design-patterns.md</a></td></tr><tr><td><strong>适配器模式</strong></td><td>Adapter Pattern</td><td>将一个接口转换为另一个接口的模式</td><td><a href="./patterns/design-patterns.html">design-patterns.md</a></td></tr><tr><td><strong>构建器模式</strong></td><td>Builder Pattern</td><td>分步骤创建复杂对象的模式</td><td><a href="./patterns/design-patterns.html">design-patterns.md</a></td></tr><tr><td><strong>单例模式</strong></td><td>Singleton Pattern</td><td>确保一个类只有一个实例的模式</td><td><a href="./patterns/design-patterns.html">design-patterns.md</a></td></tr></tbody></table><hr><h2 id="配置和命令术语" tabindex="-1">配置和命令术语 <a class="header-anchor" href="#配置和命令术语" aria-label="Permalink to &quot;配置和命令术语&quot;">​</a></h2><table tabindex="0"><thead><tr><th>中文术语</th><th>英文术语</th><th>定义/说明</th><th>首次出现文档</th></tr></thead><tbody><tr><td><strong>配置文件</strong></td><td>Config File</td><td>nanobot 的 JSON 格式配置文件，通常位于 <code>~/.nanobot/config.json</code></td><td><a href="./flow-analysis/onboard-flow.html">onboard-flow.md</a></td></tr><tr><td><strong>工作目录</strong></td><td>Workspace</td><td>nanobot 读写文件的目录，默认 <code>~/.nanobot/workspace/</code></td><td><a href="./flow-analysis/onboard-flow.html">onboard-flow.md</a></td></tr><tr><td><strong>初始化</strong></td><td>Onboard</td><td>首次运行时创建配置文件的过程</td><td><a href="./flow-analysis/onboard-flow.html">onboard-flow.md</a></td></tr><tr><td><strong>网关</strong></td><td>Gateway</td><td>连接聊天平台和代理的服务进程</td><td><a href="./flow-analysis/gateway-startup.html">gateway-startup.md</a></td></tr><tr><td><strong>代理模式</strong></td><td>Agent Mode</td><td>直接在命令行与 AI 交互的模式</td><td><a href="./flow-analysis/agent-execution.html">agent-execution.md</a></td></tr><tr><td><strong>环境变量</strong></td><td>Environment Variable</td><td>用于覆盖配置的 <code>NANOBOT__*</code> 格式的变量</td><td><a href="./flow-analysis/onboard-flow.html">onboard-flow.md</a></td></tr></tbody></table><hr><h2 id="llm-和-ai-术语" tabindex="-1">LLM 和 AI 术语 <a class="header-anchor" href="#llm-和-ai-术语" aria-label="Permalink to &quot;LLM 和 AI 术语&quot;">​</a></h2><table tabindex="0"><thead><tr><th>中文术语</th><th>英文术语</th><th>定义/说明</th><th>首次出现文档</th></tr></thead><tbody><tr><td><strong>大语言模型</strong></td><td>LLM (Large Language Model)</td><td>如 GPT-4、Claude 等大型语言模型</td><td><a href="./overview/introduction.html">introduction.md</a></td></tr><tr><td><strong>系统提示词</strong></td><td>System Prompt</td><td>发送给 LLM 的系统级指令，定义 AI 的行为和角色</td><td><a href="./modules/context-builder.html">context-builder.md</a></td></tr><tr><td><strong>函数调用</strong></td><td>Function Calling</td><td>LLM 请求执行预定义函数的能力</td><td><a href="./modules/tools.html">tools.md</a></td></tr><tr><td><strong>上下文窗口</strong></td><td>Context Window</td><td>LLM 一次能处理的最大 token 数量</td><td><a href="./modules/memory.html">memory.md</a></td></tr><tr><td><strong>Token</strong></td><td>Token</td><td>LLM 处理文本的基本单位</td><td><a href="./modules/memory.html">memory.md</a></td></tr></tbody></table><hr><h2 id="文件和目录术语" tabindex="-1">文件和目录术语 <a class="header-anchor" href="#文件和目录术语" aria-label="Permalink to &quot;文件和目录术语&quot;">​</a></h2><table tabindex="0"><thead><tr><th>中文术语</th><th>英文术语</th><th>定义/说明</th><th>路径</th></tr></thead><tbody><tr><td><strong>配置文件</strong></td><td>Config File</td><td>nanobot 主配置文件</td><td><code>~/.nanobot/config.json</code></td></tr><tr><td><strong>工作空间</strong></td><td>Workspace</td><td>数据存储目录</td><td><code>~/.nanobot/workspace/</code></td></tr><tr><td><strong>会话目录</strong></td><td>Sessions Directory</td><td>存储会话历史文件</td><td><code>~/.nanobot/workspace/sessions/</code></td></tr><tr><td><strong>技能目录</strong></td><td>Skills Directory</td><td>存储用户技能</td><td><code>~/.nanobot/workspace/skills/</code></td></tr><tr><td><strong>记忆目录</strong></td><td>Memory Directory</td><td>存储长期记忆</td><td><code>~/.nanobot/workspace/memory/</code></td></tr><tr><td><strong>长期记忆文件</strong></td><td>MEMORY.md</td><td>存储重要事实和用户偏好</td><td><code>~/.nanobot/workspace/memory/MEMORY.md</code></td></tr><tr><td><strong>历史日志文件</strong></td><td>HISTORY.md</td><td>存储压缩后的对话历史</td><td><code>~/.nanobot/workspace/memory/HISTORY.md</code></td></tr><tr><td><strong>技能文件</strong></td><td>SKILL.md</td><td>定义一个技能的 Markdown 文件</td><td><code>~/.nanobot/workspace/skills/&lt;name&gt;/SKILL.md</code></td></tr><tr><td><strong>心跳文件</strong></td><td>HEARTBEAT.md</td><td>定义定期执行的任务</td><td><code>~/.nanobot/workspace/HEARTBEAT.md</code></td></tr><tr><td><strong>任务文件</strong></td><td>jobs.json</td><td>存储定时任务配置</td><td><code>~/.nanobot/cron/jobs.json</code></td></tr></tbody></table><hr><h2 id="缩写词表" tabindex="-1">缩写词表 <a class="header-anchor" href="#缩写词表" aria-label="Permalink to &quot;缩写词表&quot;">​</a></h2><table tabindex="0"><thead><tr><th>缩写</th><th>全称</th><th>中文</th></tr></thead><tbody><tr><td>LLM</td><td>Large Language Model</td><td>大语言模型</td></tr><tr><td>AI</td><td>Artificial Intelligence</td><td>人工智能</td></tr><tr><td>JSON</td><td>JavaScript Object Notation</td><td>JSON 数据格式</td></tr><tr><td>JSONL</td><td>JSON Lines</td><td>JSON Lines 格式（每行一个 JSON）</td></tr><tr><td>API</td><td>Application Programming Interface</td><td>应用程序接口</td></tr><tr><td>CLI</td><td>Command Line Interface</td><td>命令行接口</td></tr><tr><td>async/await</td><td>asynchronous programming</td><td>异步编程</td></tr><tr><td>MCP</td><td>Model Context Protocol</td><td>模型上下文协议</td></tr></tbody></table><hr><h2 id="术语使用规范" tabindex="-1">术语使用规范 <a class="header-anchor" href="#术语使用规范" aria-label="Permalink to &quot;术语使用规范&quot;">​</a></h2><h3 id="翻译原则" tabindex="-1">翻译原则 <a class="header-anchor" href="#翻译原则" aria-label="Permalink to &quot;翻译原则&quot;">​</a></h3><ol><li><strong>优先使用中文</strong>：文档面向中文读者，优先使用中文术语</li><li><strong>首次出现标注英文</strong>：重要概念首次出现时，在括号中标注英文</li><li><strong>保持一致性</strong>：同一概念在所有文档中使用相同翻译</li></ol><h3 id="示例" tabindex="-1">示例 <a class="header-anchor" href="#示例" aria-label="Permalink to &quot;示例&quot;">​</a></h3><p><strong>✅ 正确用法</strong>：</p><ul><li>&quot;代理（Agent）接收消息后...&quot;</li><li>&quot;使用消息总线（MessageBus）解耦组件...&quot;</li><li>&quot;调用工具（Tool）执行操作...&quot;</li></ul><p><strong>❌ 避免使用</strong>：</p><ul><li>&quot;Agent 接收消息...&quot;（缺少中文翻译）</li><li>&quot;Message Bus 解耦...&quot;（大小写不规范）</li><li>&quot;agent 接收消息...&quot;（术语应该小写？）</li></ul><h3 id="特殊情况" tabindex="-1">特殊情况 <a class="header-anchor" href="#特殊情况" aria-label="Permalink to &quot;特殊情况&quot;">​</a></h3><p>某些专业术语保留英文：</p><ul><li>API、CLI、JSON、JSONL 等业界通用缩写</li><li>asyncio、pytest、ruff 等 Python 库名称</li><li>Telegram、Discord、WhatsApp 等平台名称</li></ul><hr><h2 id="更新记录" tabindex="-1">更新记录 <a class="header-anchor" href="#更新记录" aria-label="Permalink to &quot;更新记录&quot;">​</a></h2><table tabindex="0"><thead><tr><th>日期</th><th>版本</th><th>更新内容</th></tr></thead><tbody><tr><td>2026-03-12</td><td>v1.0.0</td><td>初始版本，定义核心术语</td></tr></tbody></table><hr><blockquote><p>💡 <strong>提示</strong>：如果您在文档中发现不一致的术语使用，请参考本表统一修正，或更新本表添加新术语。</p></blockquote>',41)])])}const b=d(a,[["render",n]]);export{c as __pageData,b as default};
